  // ── Budgets ──
  "bud.eyebrow": { en: "This month", ru: "Этот месяц", uk: "Цей місяць", ro: "Luna aceasta", de: "Dieser Monat", es: "Este mes", it: "Questo mese", pl: "Ten miesiąc", ja: "今月", ka: "ამ თვეში" },
  "bud.subtitle": { en: "Set a monthly limit per category. Lumi tracks spend in real time and warns you before you hit the ceiling.", ru: "Задайте месячный лимит по категории. Lumi отслеживает расходы в реальном времени и предупреждает до превышения.", uk: "Задайте місячний ліміт за категорією. Lumi відстежує витрати в реальному часі й попереджає до перевищення.", ro: "Setează o limită lunară per categorie. Lumi urmărește cheltuielile în timp real și te avertizează înainte de depășire.", de: "Lege ein monatliches Limit pro Kategorie fest. Lumi verfolgt Ausgaben in Echtzeit und warnt dich vor dem Überschreiten.", es: "Fija un límite mensual por categoría. Lumi controla el gasto en tiempo real y te avisa antes de pasarte.", it: "Imposta un limite mensile per categoria. Lumi monitora le spese in tempo reale e ti avvisa prima di sforare.", pl: "Ustaw miesięczny limit dla kategorii. Lumi śledzi wydatki na bieżąco i ostrzega przed przekroczeniem.", ja: "カテゴリごとに月間上限を設定。Lumiが支出をリアルタイムで追跡し、超過前に警告します。", ka: "დააწესეთ თვიური ლიმიტი კატეგორიაზე. Lumi ადევნებს ხარჯს რეალურ დროში და გაფრთხილებთ ლიმიტამდე." },
  "bud.new": { en: "+ New budget", ru: "+ Новый бюджет", uk: "+ Новий бюджет", ro: "+ Buget nou", de: "+ Neues Budget", es: "+ Nuevo presupuesto", it: "+ Nuovo budget", pl: "+ Nowy budżet", ja: "＋ 新しい予算", ka: "+ ახალი ბიუჯეტი" },
  "bud.create": { en: "Create budget", ru: "Создать бюджет", uk: "Створити бюджет", ro: "Creează buget", de: "Budget erstellen", es: "Crear presupuesto", it: "Crea budget", pl: "Utwórz budżet", ja: "予算を作成", ka: "ბიუჯეტის შექმნა" },
