  // ── Forecast ──
  "fc.subtitle": { en: "Lumi projects your month-end spend from your current daily rate, then compares it against your budgets.", ru: "Lumi прогнозирует расходы на конец месяца по текущему дневному темпу и сравнивает их с бюджетами.", uk: "Lumi прогнозує витрати на кінець місяця за поточним денним темпом і порівнює їх із бюджетами.", ro: "Lumi estimează cheltuielile de la finalul lunii pe baza ritmului zilnic actual și le compară cu bugetele.", de: "Lumi prognostiziert deine Ausgaben zum Monatsende anhand deiner aktuellen Tagesrate und vergleicht sie mit deinen Budgets.", es: "Lumi proyecta tu gasto a fin de mes según tu ritmo diario actual y lo compara con tus presupuestos.", it: "Lumi proietta la spesa di fine mese in base al ritmo giornaliero attuale e la confronta con i tuoi budget.", pl: "Lumi prognozuje wydatki na koniec miesiąca na podstawie bieżącego tempa dziennego i porównuje je z budżetami.", ja: "Lumiは現在の1日あたりの支出ペースから月末支出を予測し、予算と比較します。", ka: "Lumi პროგნოზირებს თვის ბოლოს ხარჯს მიმდინარე დღიური ტემპით და ადარებს ბიუჯეტებს." },
  "fc.onTrack": { en: "On track", ru: "В норме", uk: "У нормі", ro: "În grafic", de: "Im Plan", es: "En camino", it: "In linea", pl: "Zgodnie z planem", ja: "順調", ka: "გეგმის მიხედვით" },
  "fc.watch": { en: "Watch spending", ru: "Следите за тратами", uk: "Стежте за витратами", ro: "Atenție la cheltuieli", de: "Ausgaben beobachten", es: "Cuidado con el gasto", it: "Occhio alle spese", pl: "Uważaj na wydatki", ja: "支出に注意", ka: "ადევნეთ თვალი ხარჯებს" },
  "fc.over": { en: "Heading over budget", ru: "Превышение бюджета", uk: "Перевищення бюджету", ro: "Depășești bugetul", de: "Über Budget", es: "Te pasas del presupuesto", it: "Oltre il budget", pl: "Przekraczasz budżet", ja: "予算超過の見込み", ka: "ბიუჯეტს გადააჭარბებთ" },
