  "lp.navFeatures": { en: "Features", ru: "Возможности", uk: "Можливості", ro: "Funcții", de: "Funktionen", es: "Funciones", it: "Funzioni", pl: "Funkcje", ja: "機能", ka: "ფუნქციები" },
