  "lp.download": { en: "Download", ru: "Скачать", uk: "Завантажити", ro: "Descarcă", de: "Herunterladen", es: "Descargar", it: "Scarica", pl: "Pobierz", ja: "ダウンロード", ka: "ჩამოტვირთვა" },

  "lp.heroLabel": { en: "Available on the App Store", ru: "Доступно в App Store", uk: "Доступно в App Store", ro: "Disponibil în App Store", de: "Verfügbar im App Store", es: "Disponible en la App Store", it: "Disponibile su App Store", pl: "Dostępne w App Store", ja: "App Store で配信中", ka: "ხელმისაწვდომია App Store-ში" },
  "lp.heroTitle1": { en: "Know your money.", ru: "Знай свои деньги.", uk: "Знай свої гроші.", ro: "Cunoaște-ți banii.", de: "Kenne dein Geld.", es: "Conoce tu dinero.", it: "Conosci i tuoi soldi.", pl: "Poznaj swoje pieniądze.", ja: "お金を把握しよう。", ka: "იცოდე შენი ფული." },
  "lp.heroTitle2": { en: "Before it's gone.", ru: "Пока они не исчезли.", uk: "Поки вони не зникли.", ro: "Înainte să dispară.", de: "Bevor es weg ist.", es: "Antes de que desaparezca.", it: "Prima che spariscano.", pl: "Zanim znikną.", ja: "なくなる前に。", ka: "სანამ გაქრება." },
  "lp.heroSubtitle": { en: "Back Tap your iPhone to log an expense in 2 seconds. Apple Pay auto-imports the moment you pay. AI forecasts your month-end balance before you overspend.", ru: "Дважды коснись задней панели iPhone — и расход записан за 2 секунды. Apple Pay импортирует траты автоматически. ИИ прогнозирует баланс на конец месяца до перерасхода.", uk: "Подвійний тап по задній панелі iPhone — витрата записана за 2 секунди. Apple Pay імпортує автоматично. ШІ прогнозує баланс на кінець місяця до перевитрат.", ro: "Un Back Tap pe iPhone înregistrează o cheltuială în 2 secunde. Apple Pay importă automat. IA prognozează soldul la final de lună înainte să cheltuiești prea mult.", de: "Back Tap auf dem iPhone erfasst eine Ausgabe in 2 Sekunden. Apple Pay importiert automatisch. KI prognostiziert deinen Monatsendsaldo, bevor du zu viel ausgibst.", es: "Un Back Tap en tu iPhone registra un gasto en 2 segundos. Apple Pay importa automáticamente. La IA prevé tu saldo de fin de mes antes de que gastes de más.", it: "Un Back Tap sull'iPhone registra una spesa in 2 secondi. Apple Pay importa in automatico. L'IA prevede il saldo di fine mese prima che tu spenda troppo.", pl: "Back Tap w iPhonie zapisuje wydatek w 2 sekundy. Apple Pay importuje automatycznie. AI prognozuje saldo na koniec miesiąca, zanim przekroczysz budżet.", ja: "iPhone の背面タップで2秒で支出を記録。Apple Pay が支払い時に自動取り込み。AI が使いすぎる前に月末残高を予測します。", ka: "iPhone-ის უკანა შეხებით ხარჯი 2 წამში ჩაიწერება. Apple Pay ავტომატურად აიმპორტებს. AI პროგნოზირებს თვის ბოლოს ბალანსს გადახარჯვამდე." },
